// ============================================
// Wallet Manager
// ============================================
class WalletManager {
    constructor() {
        this.wallets = new Map();
        this.providers = new Map();
    }

    getProvider(networkName) {
        if (this.providers.has(networkName)) {
            return this.providers.get(networkName);
        }

        const rpcUrl = config.networks[networkName];
        if (!rpcUrl) {
            throw new Error(`Unknown network: ${networkName}`);
        }

        const provider = new ethers.JsonRpcProvider(rpcUrl);
        this.providers.set(networkName, provider);
        return provider;
    }

    addWalletFromPrivateKey(name, privateKey, networkName = config.defaultNetwork) {
        if (!privateKey) {
            throw new Error('Private key is required');
        }

        // Ensure private key has 0x prefix
        const formattedKey = privateKey.startsWith('0x') ? privateKey : `0x${privateKey}`;

        const provider = this.getProvider(networkName);
        const wallet = new ethers.Wallet(formattedKey, provider);

        this.wallets.set(name, {
            wallet,
            network: networkName,
            address: wallet.address
        });

        console.log(`Wallet "${name}" added: ${wallet.address} on ${networkName}`);
        return wallet.address;
    }

    addWalletFromMnemonic(name, mnemonic, path = "m/44'/60'/0'/0/0", networkName = config.defaultNetwork) {
        const provider = this.getProvider(networkName);
        const hdNode = ethers.HDNodeWallet.fromPhrase(mnemonic, undefined, path);
        const wallet = hdNode.connect(provider);

        this.wallets.set(name, {
            wallet,
            network: networkName,
            address: wallet.address
        });

        console.log(`Wallet "${name}" added from mnemonic: ${wallet.address} on ${networkName}`);
        return wallet.address;
    }

    getWallet(name) {
        const entry = this.wallets.get(name);
        if (!entry) {
            throw new Error(`Wallet "${name}" not found`);
        }
        return entry.wallet;
    }

    getWalletInfo(name) {
        const entry = this.wallets.get(name);
        if (!entry) {
            throw new Error(`Wallet "${name}" not found`);
        }
        return {
            address: entry.address,
            network: entry.network
        };
    }

    listWallets() {
        const walletList = [];
        for (const [name, entry] of this.wallets) {
            walletList.push({
                name,
                address: entry.address,
                network: entry.network
            });
        }
        return walletList;
    }
}

// ============================================
// Transaction Service
// ============================================
class TransactionService {
    constructor(walletManager) {
        this.walletManager = walletManager;
    }

    async getBalance(walletName) {
        const wallet = this.walletManager.getWallet(walletName);
        const balance = await wallet.provider.getBalance(wallet.address);
        return {
            wei: balance.toString(),
            ether: ethers.formatEther(balance)
        };
    }

    async getBalanceOfAddress(address, networkName = config.defaultNetwork) {
        const provider = this.walletManager.getProvider(networkName);
        const balance = await provider.getBalance(address);
        return {
            wei: balance.toString(),
            ether: ethers.formatEther(balance)
        };
    }

    async sendETH(fromWalletName, toAddress, amountInEther, options = {}) {
        const wallet = this.walletManager.getWallet(fromWalletName);

        // Validate address
        if (!ethers.isAddress(toAddress)) {
            throw new Error(`Invalid address: ${toAddress}`);
        }

        // Build transaction
        const tx = {
            to: toAddress,
            value: ethers.parseEther(amountInEther.toString()),
        };

        // Gas settings
        if (options.gasLimit) {
            tx.gasLimit = options.gasLimit;
        }

        if (options.maxFeePerGas) {
            tx.maxFeePerGas = ethers.parseUnits(options.maxFeePerGas.toString(), 'gwei');
        }

        if (options.maxPriorityFeePerGas) {
            tx.maxPriorityFeePerGas = ethers.parseUnits(options.maxPriorityFeePerGas.toString(), 'gwei');
        }

        if (options.nonce !== undefined) {
            tx.nonce = options.nonce;
        }

        console.log(`Sending ${amountInEther} ETH from ${wallet.address} to ${toAddress}...`);

        // Estimate gas if not provided
        if (!tx.gasLimit) {
            try {
                const estimatedGas = await wallet.estimateGas(tx);
                tx.gasLimit = estimatedGas * 120n / 100n; // Add 20% buffer
            } catch (error) {
                console.warn('Gas estimation failed, using default:', error.message);
                tx.gasLimit = config.gasLimit;
            }
        }

        // Send transaction
        const txResponse = await wallet.sendTransaction(tx);
        console.log(`Transaction sent: ${txResponse.hash}`);

        // Wait for confirmation if requested
        if (options.waitConfirmations) {
            console.log(`Waiting for ${options.waitConfirmations} confirmation(s)...`);
            const receipt = await txResponse.wait(options.waitConfirmations);
            console.log(`Transaction confirmed in block ${receipt.blockNumber}`);
            return {
                hash: txResponse.hash,
                receipt: {
                    blockNumber: receipt.blockNumber,
                    blockHash: receipt.blockHash,
                    gasUsed: receipt.gasUsed.toString(),
                    effectiveGasPrice: receipt.gasPrice.toString(),
                    status: receipt.status
                }
            };
        }

        return {
            hash: txResponse.hash,
            nonce: txResponse.nonce,
            from: txResponse.from,
            to: txResponse.to,
            value: txResponse.value.toString()
        };
    }

    async getTransactionReceipt(txHash, networkName = config.defaultNetwork) {
        const provider = this.walletManager.getProvider(networkName);
        const receipt = await provider.getTransactionReceipt(txHash);
        if (!receipt) {
            return null;
        }
        return {
            blockNumber: receipt.blockNumber,
            blockHash: receipt.blockHash,
            transactionHash: receipt.hash,
            from: receipt.from,
            to: receipt.to,
            gasUsed: receipt.gasUsed.toString(),
            effectiveGasPrice: receipt.gasPrice.toString(),
            status: receipt.status,
            logs: receipt.logs.map(log => ({
                address: log.address,
                topics: log.topics,
                data: log.data
            }))
        };
    }

    async getGasPrice(networkName = config.defaultNetwork) {
        const provider = this.walletManager.getProvider(networkName);
        const feeData = await provider.getFeeData();
        return {
            gasPrice: feeData.gasPrice ? ethers.formatUnits(feeData.gasPrice, 'gwei') + ' gwei' : null,
            maxFeePerGas: feeData.maxFeePerGas ? ethers.formatUnits(feeData.maxFeePerGas, 'gwei') + ' gwei' : null,
            maxPriorityFeePerGas: feeData.maxPriorityFeePerGas ? ethers.formatUnits(feeData.maxPriorityFeePerGas, 'gwei') + ' gwei' : null
        };
    }

    async getNonce(walletName) {
        const wallet = this.walletManager.getWallet(walletName);
        return await wallet.getNonce();
    }
}

